def NOT(a):
    """NOT gate."""
    return 1 if a == 0 else 0

def AND(a, b):
    """AND gate."""
    return 1 if (a == 1 and b == 1) else 0

def OR(a, b):
    """OR gate."""
    return 1 if (a == 1 or b == 1) else 0

def XOR(a, b):
    """XOR gate."""
    return 1 if a != b else 0

def NAND(a, b):
    """NAND gate."""
    return NOT(AND(a, b))

def NOR(a, b):
    """NOR gate."""
    return NOT(OR(a, b))

def print_truth_table(gate_func, name, num_inputs=2):
    """
    Print truth table for a gate.
    """
    print(f"\n{name} Gate:")

    if num_inputs == 1:
        print(" A | Output")
        print("---|-------")
        for a in [0, 1]:
            result = gate_func(a)
            print(f" {a} |   {result}")
    else:
        print(" A | B | Output")
        print("---|---|-------")
        for a in [0, 1]:
            for b in [0, 1]:
                result = gate_func(a, b)
                print(f" {a} | {b} |   {result}")

# Test all gates
print("=== Basic Logic Gates ===")
print_truth_table(NOT, "NOT", num_inputs=1)
print_truth_table(AND, "AND")
print_truth_table(OR, "OR")
print_truth_table(XOR, "XOR")
print_truth_table(NAND, "NAND")
print_truth_table(NOR, "NOR")

# Verify XOR self-inverse property
print("\n=== XOR Self-Inverse Property ===")
for a in [0, 1]:
    for b in [0, 1]:
        result = XOR(XOR(a, b), b)
        print(f"{a} XOR {b} XOR {b} = {result} (should equal {a})")
